jq -r 'select(.type=="response_item" and .payload.type=="function_call") | (.payload.arguments|fromjson? // {}) | .cmd // empty' "${f}" | rg 'healthcheck|run_attendance|preflight|inspect_runtime|validate_offline|month_gate|cat .*/automation.toml' | head -60
