jq -r 'select(.type=="response_item" and .payload.type=="message" and .payload.role=="assistant") | [.payload.content[]? | select(.type=="output_text") | .text] | join("\\n")' "${f}" | tail -55`,"workdir":"[REDACTED_LOCAL_PATH]","yield_time_ms":10000,"max_output_tokens":24000});
 text(`FILE ${f}\n${r.output}`);
}

